import type { Targetable } from "./schema.js";
/**
 * Variables that recur across flows. Spread into a flow's `variables` map to
 * pick up the shared value. Keeping them in one place ensures every flow
 * uses the same wording — particularly important for per-target divergences
 * where claude/cursor and codex want different phrasings of the same idea.
 *
 * Usage:
 *
 *   variables: {
 *     ...SHARED_VARIABLES,
 *     flowSpecificVar: "...",
 *   }
 *
 * Add a new entry here when the same Targetable string would be defined
 * verbatim in two or more flows. Don't add per-flow content here.
 */
export declare const SHARED_VARIABLES: Record<string, string | Targetable<string>>;
